import React, { useEffect, useState } from "react";
import axios from "axios";

const API_URL = "http://localhost:5000/api/features";

const priorities = ["Low", "Medium", "High"];
const statuses = ["Open", "In Progress", "Completed"];

export default function AdminDashboard() {
  const [features, setFeatures] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [errorDetails, setErrorDetails] = useState(null);
  const [editingId, setEditingId] = useState(null);
  const [editData, setEditData] = useState({});
  const [newFeature, setNewFeature] = useState({ title: "", description: "", priority: "Low", status: "Open" });
  const [adding, setAdding] = useState(false);
  const [showPriorityDialog, setShowPriorityDialog] = useState(false);
  const [lastAddedId, setLastAddedId] = useState(null);
  const [priorityToSet, setPriorityToSet] = useState("Low");

  // Fetch features
  const fetchFeatures = () => {
    setLoading(true);
    setError(null);
    setErrorDetails(null);
    axios.get(API_URL)
      .then(res => setFeatures(res.data))
      .catch(err => {
        setError("Failed to fetch features");
        setErrorDetails(err?.message || JSON.stringify(err));
        console.error("Fetch features error:", err);
      })
      .finally(() => setLoading(false));
  };

  useEffect(() => { fetchFeatures(); }, []);

  // Delete feature
  const handleDelete = async (id) => {
    if (!window.confirm("Delete this feature?")) return;
    try {
      await axios.delete(`${API_URL}/${id}`);
      setFeatures(f => f.filter(feat => feat.id !== id));
    } catch (err) {
      setError("Failed to delete feature");
      setErrorDetails(err?.message || JSON.stringify(err));
      console.error("Delete feature error:", err);
    }
  };

  // Start editing
  const handleEdit = (f) => {
    setEditingId(f.id);
    setEditData({ ...f });
  };

  // Save edit
  const handleSave = async (id) => {
    try {
      await axios.put(`${API_URL}/${id}`, editData);
      setEditingId(null);
      fetchFeatures();
    } catch (err) {
      setError("Failed to update feature");
      setErrorDetails(err?.message || JSON.stringify(err));
      console.error("Update feature error:", err);
    }
  };

  // Add new feature
  const handleAdd = async () => {
    try {
      const res = await axios.post(API_URL, newFeature);
      setNewFeature({ title: "", description: "", priority: "Low", status: "Open" });
      setAdding(false);
      // Show dialog to set priority after add
      const addedId = res.data?.id || (res.data && res.data.insertId) || null;
      setLastAddedId(addedId);
      setPriorityToSet(newFeature.priority);
      setShowPriorityDialog(true);
      fetchFeatures();
    } catch (err) {
      setError("Failed to add feature");
      setErrorDetails(err?.message || JSON.stringify(err));
      console.error("Add feature error:", err);
    }
  };

  return (
    <div style={{ maxWidth: 900, margin: "40px auto", background: "#fff", borderRadius: 12, padding: 32, color: '#222' }}>
      <h2 style={{ fontSize: 28, marginBottom: 24 }}>Admin Feature Management</h2>
      {loading && <p>Loading...</p>}
      {error && (
        <div style={{ color: 'red', marginBottom: 12 }}>
          <p>{error}</p>
          {errorDetails && (
            <details style={{ fontSize: 13, marginTop: 4 }}>
              <summary>Details</summary>
              <pre style={{ whiteSpace: 'pre-wrap' }}>{errorDetails}</pre>
            </details>
          )}
          <button onClick={fetchFeatures} style={{ marginTop: 8 }}>Retry</button>
        </div>
      )}

      {/* Add new feature */}
      {adding ? (
        <div style={{ marginBottom: 24, background: '#f9f9f9', padding: 16, borderRadius: 8 }}>
          <input
            placeholder="Title"
            value={newFeature.title}
            onChange={e => setNewFeature(n => ({ ...n, title: e.target.value }))}
            style={{ marginRight: 8, padding: 4 }}
          />
          <input
            placeholder="Description"
            value={newFeature.description}
            onChange={e => setNewFeature(n => ({ ...n, description: e.target.value }))}
            style={{ marginRight: 8, padding: 4 }}
          />
          <select value={newFeature.priority} onChange={e => setNewFeature(n => ({ ...n, priority: e.target.value }))} style={{ marginRight: 8 }}>
            {priorities.map(p => <option key={p}>{p}</option>)}
          </select>
          <select value={newFeature.status} onChange={e => setNewFeature(n => ({ ...n, status: e.target.value }))} style={{ marginRight: 8 }}>
            {statuses.map(s => <option key={s}>{s}</option>)}
          </select>
          <button onClick={handleAdd} style={{ marginRight: 8 }}>Add</button>
          <button onClick={() => setAdding(false)}>Cancel</button>
        </div>
      ) : (
        <button onClick={() => setAdding(true)} style={{ marginBottom: 24 }}>+ Add Feature</button>
      )}

      {/* Priority dialog/modal after add */}
      {showPriorityDialog && lastAddedId && (
        <div style={{
          position: 'fixed', top: 0, left: 0, width: '100vw', height: '100vh',
          background: 'rgba(0,0,0,0.3)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000
        }}>
          <div style={{ background: '#fff', padding: 32, borderRadius: 12, minWidth: 320, boxShadow: '0 2px 16px #0002' }}>
            <h3 style={{ marginBottom: 16 }}>Set Priority for New Feature</h3>
            <select value={priorityToSet} onChange={e => setPriorityToSet(e.target.value)} style={{ marginBottom: 16, width: '100%', padding: 8 }}>
              {priorities.map(p => <option key={p}>{p}</option>)}
            </select>
            <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
              <button
                onClick={async () => {
                  try {
                    await axios.put(`${API_URL}/${lastAddedId}`, { priority: priorityToSet });
                    setShowPriorityDialog(false);
                    setLastAddedId(null);
                    fetchFeatures();
                  } catch (err) {
                    alert('Failed to update priority.');
                  }
                }}
                style={{ marginRight: 8 }}
              >Save</button>
              <button onClick={() => { setShowPriorityDialog(false); setLastAddedId(null); }}>Cancel</button>
            </div>
          </div>
        </div>
      )}

      <table style={{ width: "100%", borderCollapse: "collapse", background: "transparent" }}>
        <thead>
          <tr style={{ background: "#f0f0f0" }}>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>ID</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Title</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Priority</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Status</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Created</th>
            <th style={{ textAlign: "left", padding: "10px 8px" }}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {features.map(f => (
            <tr key={f.id} style={{ borderBottom: "1px solid #eee" }}>
              <td style={{ padding: "10px 8px" }}>{f.id}</td>
              <td style={{ padding: "10px 8px" }}>
                {editingId === f.id ? (
                  <input value={editData.title} onChange={e => setEditData(d => ({ ...d, title: e.target.value }))} />
                ) : f.title}
              </td>
              <td style={{ padding: "10px 8px" }}>
                {editingId === f.id ? (
                  <select value={editData.priority} onChange={e => setEditData(d => ({ ...d, priority: e.target.value }))}>
                    {priorities.map(p => <option key={p}>{p}</option>)}
                  </select>
                ) : f.priority}
              </td>
              <td style={{ padding: "10px 8px" }}>
                {editingId === f.id ? (
                  <select value={editData.status} onChange={e => setEditData(d => ({ ...d, status: e.target.value }))}>
                    {statuses.map(s => <option key={s}>{s}</option>)}
                  </select>
                ) : f.status}
              </td>
              <td style={{ padding: "10px 8px" }}>{new Date(f.createdAt).toLocaleString()}</td>
              <td style={{ padding: "10px 8px" }}>
                {editingId === f.id ? (
                  <>
                    <button onClick={() => handleSave(f.id)} style={{ marginRight: 6 }}>Save</button>
                    <button onClick={() => setEditingId(null)}>Cancel</button>
                  </>
                ) : (
                  <>
                    <button onClick={() => handleEdit(f)} style={{ marginRight: 6 }}>Edit</button>
                    <button onClick={() => handleDelete(f.id)} style={{ color: 'red' }}>Delete</button>
                  </>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
